mapper.select:
SELECT
    -- 累计指标
    (SELECT COUNT(*) FROM sys_user) AS totalUsers,
    (SELECT COUNT(*) FROM sys_user WHERE is_creator = 1) AS totalCreators,
    (SELECT COUNT(*) FROM audio_info WHERE is_deleted = 0) AS totalAudios,
    (SELECT COUNT(*) FROM audio_info WHERE audit_status = 1 AND is_deleted = 0) AS approvedAudios,
    (SELECT COALESCE(SUM(play_count), 0) FROM audio_info WHERE is_deleted = 0) AS totalPlays,
    (SELECT COALESCE(SUM(pay_amount), 0) FROM audio_order WHERE pay_status = 1) AS totalAudioSales,
    (SELECT COALESCE(SUM(recharge_amount), 0) FROM user_recharge_order WHERE pay_status = 'PAID') AS totalRecharge,
    (SELECT COALESCE(SUM(pay_amount), 0) FROM consult_order WHERE status = 'COMPLETED') AS totalConsultSales,
    (SELECT COUNT(*) FROM audio_folder_relation) AS totalCollects,
    (SELECT COUNT(*) FROM audio_like) AS totalLikes,
    (SELECT COUNT(*) FROM comments) AS totalComments,

    -- 时间段内新增指标


            (SELECT COUNT(*) FROM sys_user

                 create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newUsers,
            (SELECT COUNT(*) FROM sys_user

                 is_creator = 1
                 AND create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newCreators,
            (SELECT COUNT(*) FROM audio_info

                 is_deleted = 0
                 AND create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newAudios,
            (SELECT COUNT(*) FROM audio_info

                 audit_status = 1 AND is_deleted = 0
                 AND create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newApprovedAudios,
            (SELECT COUNT(*) FROM audio_folder_relation

                 create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newCollects,
            (SELECT COUNT(*) FROM audio_like

                 create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newLikes,
            (SELECT COUNT(*) FROM comments

                 create_time >= #{startDate}
                 AND create_time <= #{endDate}

            ) AS newComments


            0 AS newUsers, 0 AS newCreators, 0 AS newAudios, 0 AS newApprovedAudios,
            0 AS newCollects, 0 AS newLikes, 0 AS newComments


FROM DUAL
